import React, { useEffect } from 'react';
import { Typography, Card, CardMedia, CardContent } from '@mui/material';
import { Link, useParams } from 'react-router-dom';
import fetchModel from '../../modelData/models';

const UserPhotos = ({ setContext }) => {
  const { userId } = useParams();
  const photos = fetchModel.photoOfUserModel(userId);
  const user = fetchModel.userModel(userId);

  useEffect(() => {
    if (user) {
      setContext(`Photos of ${user.first_name} ${user.last_name}`);
    }
  }, [user, setContext]);

  return (
    <div>
      {photos.map((photo) => (
        <Card key={photo._id} style={{ marginBottom: '20px' }}>
          <CardMedia
            component="img"
            image={`/images/${photo.kenobi2.jpg}`} // Đường dẫn tới thư mục ảnh
            alt="User uploaded"
          />
          <CardContent>
            <Typography variant="caption" color="textSecondary">
              Posted on: {new Date(photo.date_time).toLocaleString()}
            </Typography>

            <Typography variant="h6" style={{ marginTop: '10px' }}>Comments:</Typography>
            {photo.comments && photo.comments.map(comment => (
              <div key={comment._id} style={{ marginTop: '5px', borderBottom: '1px solid #eee' }}>
                <Typography variant="body2">
                  <Link to={`/users/${comment.user._id}`}>
                    <strong>{comment.user.first_name} {comment.user.last_name}</strong>
                  </Link>
                  : {comment.comment}
                </Typography>
                <Typography variant="caption" color="textSecondary">
                  {new Date(comment.date_time).toLocaleString()}
                </Typography>
              </div>
            ))}
          </CardContent>
        </Card>
      ))}
    </div>
  );
};

export default UserPhotos;
